package com.establo.controller;import com.establo.dto.*;import com.establo.service.*;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.data.web.PageableDefault;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api") @RequiredArgsConstructor public class SupplyController {private final SupplyService s;private final SupplyRecordService records;@GetMapping("/inventory") List<InventoryItemDto> inventory(){return s.inventory();}@GetMapping("/inventory/search") Page<InventoryItemDto> inventorySearch(@RequestParam(required=false)String q,@RequestParam(required=false)String category,@RequestParam(required=false)Boolean lowStock,@PageableDefault(size=20,sort="name")Pageable pageable){return s.searchInventory(q,category,lowStock,pageable);}@PostMapping("/inventory") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") ResponseEntity<InventoryItemDto> add(@Valid @RequestBody InventoryItemDto d){return ResponseEntity.status(201).body(s.saveItem(null,d));}@PutMapping("/inventory/{id}") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") InventoryItemDto edit(@PathVariable Long id,@Valid @RequestBody InventoryItemDto d){return s.saveItem(id,d);}@DeleteMapping("/inventory/{id}") @PreAuthorize("hasRole('ADMIN')") @ResponseStatus(HttpStatus.NO_CONTENT) void del(@PathVariable Long id){s.deleteItem(id);}@GetMapping("/feeding-plans") List<FeedingPlanDto> plans(){return s.plans();}@PostMapping("/feeding-plans") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") ResponseEntity<FeedingPlanDto> addPlan(@Valid @RequestBody FeedingPlanDto d){return ResponseEntity.status(201).body(s.savePlan(null,d));}@PutMapping("/feeding-plans/{id}") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") FeedingPlanDto editPlan(@PathVariable Long id,@Valid @RequestBody FeedingPlanDto d){return s.savePlan(id,d);}@DeleteMapping("/feeding-plans/{id}") @PreAuthorize("hasRole('ADMIN')") @ResponseStatus(HttpStatus.NO_CONTENT) void delPlan(@PathVariable Long id){s.deletePlan(id);}@GetMapping("/supply-records") List<SupplyRecordDto> records(){return records.all();}@PostMapping("/supply-records") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") ResponseEntity<SupplyRecordDto> addRecord(@Valid @RequestBody SupplyRecordDto d){return ResponseEntity.status(201).body(records.create(d));}@DeleteMapping("/supply-records/{id}") @PreAuthorize("hasRole('ADMIN')") @ResponseStatus(HttpStatus.NO_CONTENT) void deleteRecord(@PathVariable Long id){records.delete(id);}}
